/* ══════════════════════════════════════════════
   STORAGE — localStorage 기반 (Vercel 배포용)
══════════════════════════════════════════════ */
const store = {
  get: async (key) => {
    try {
      const v = localStorage.getItem(key);
      return v !== null ? { value: v } : null;
    } catch { return null; }
  },
  set: async (key, val) => {
    try { localStorage.setItem(key, val); return true; } catch { return null; }
  },
  list: async (prefix) => {
    try {
      const keys = Object.keys(localStorage).filter(k => k.startsWith(prefix));
      return { keys };
    } catch { return { keys: [] }; }
  }
};

/* ══════════════════════════════════════════════
   HELPERS
══════════════════════════════════════════════ */
const toKey = (d) => `${d.getFullYear()}-${p2(d.getMonth()+1)}-${p2(d.getDate())}`;
const todayKey = () => toKey(new Date());
const p2 = (n) => String(n).padStart(2,"0");
const fmtTime = (s) => `${p2(Math.floor(s/60))}:${p2(s%60)}`;
const timeToMins = (t) => { const [h,m]=t.split(":").map(Number); return h*60+m; };
const calcDuration = (start, end) => {
  let d = timeToMins(end) - timeToMins(start);
  if (d < 0) d += 24*60;
  return d;
};

