/* ══════════════════════════════════════════════
   고미 CHARACTER SVG (Bear costume - warm brown)
══════════════════════════════════════════════ */
function GomiCharacter({ minutes, goal }) {
  const pct = goal > 0 ? Math.min(minutes / goal, 1) : 0;
  const SIZE = 180; // svg canvas
  const CX = SIZE/2, CY = SIZE/2;
  const R = 82; // ring radius — large & visible
  const circ = 2*Math.PI*R, dash = circ*pct;
  const IMG_SIZE = 100; // character image size (smaller)

  return (
    <div style={{ display:"flex", flexDirection:"column", alignItems:"center", paddingTop:8 }}>
      <div style={{ background:"linear-gradient(135deg,#B45309,#D97706)", color:"#fff", borderRadius:20, padding:"5px 18px", fontSize:13, fontWeight:700, marginBottom:6, boxShadow:"0 4px 16px rgba(180,83,9,0.3)", animation:"floatUp 3s ease-in-out infinite" }}>
        오늘 {minutes}분 수행{goal>0&&<span style={{opacity:0.75,fontWeight:400}}> / 목표 {goal}분</span>}
      </div>
      <div style={{ position:"relative", width:SIZE, height:SIZE, display:"flex", alignItems:"center", justifyContent:"center" }}>
        {/* Ring — always rendered when goal > 0, thick and clear */}
        {goal>0 ? (
          <svg width={SIZE} height={SIZE} style={{ position:"absolute", top:0, left:0 }}>
            {/* Track */}
            <circle cx={CX} cy={CY} r={R} fill="none" stroke="#FDE68A" strokeWidth="10"/>
            {/* Progress */}
            <circle cx={CX} cy={CY} r={R} fill="none" stroke="#D97706" strokeWidth="10"
              strokeDasharray={`${dash} ${circ}`} strokeLinecap="round"
              transform={`rotate(-90 ${CX} ${CY})`}
              style={{transition:"stroke-dasharray 0.6s ease"}}/>
            {/* Percentage text inside ring */}
            <text x={CX} y={CY+38} textAnchor="middle" fontSize="12" fill="#B45309" fontWeight="700">
              {Math.round(pct*100)}%
            </text>
          </svg>
        ) : (
          <svg width={SIZE} height={SIZE} style={{ position:"absolute", top:0, left:0 }}>
            <circle cx={CX} cy={CY} r={R} fill="none" stroke="#FEF3C7" strokeWidth="6" strokeDasharray="6 4"/>
          </svg>
        )}
        <img src={GOMI_IMG} alt="고미"
          style={{ width:IMG_SIZE, height:IMG_SIZE, objectFit:"contain", position:"relative", zIndex:1,
            filter:"drop-shadow(0 3px 10px rgba(180,83,9,0.18))" }}/>

        {/* Sparkles around character */}
        <svg width={SIZE} height={SIZE} style={{position:"absolute",top:0,left:0,pointerEvents:"none",zIndex:2}}>
          {[
            {cx:30, cy:42, r:3.5, delay:0,    color:"#FDE68A"},
            {cx:148,cy:38, r:2.5, delay:0.4,  color:"#F472B6"},
            {cx:22, cy:105,r:3,   delay:0.8,  color:"#D97706"},
            {cx:155,cy:100,r:2.5, delay:1.2,  color:"#FDE68A"},
            {cx:55, cy:25, r:2,   delay:1.6,  color:"#F472B6"},
            {cx:128,cy:28, r:3,   delay:2.0,  color:"#D97706"},
            {cx:18, cy:70, r:2,   delay:2.4,  color:"#FDE68A"},
            {cx:160,cy:65, r:2.5, delay:2.8,  color:"#F472B6"},
          ].map((s,i)=>(
            <g key={i}>
              <circle cx={s.cx} cy={s.cy} r={s.r} fill={s.color}
                style={{animation:`sparkleGomi 2.4s ${s.delay}s ease-in-out infinite`}}/>
              {/* Cross sparkle */}
              <line x1={s.cx-s.r*1.6} y1={s.cy} x2={s.cx+s.r*1.6} y2={s.cy}
                stroke={s.color} strokeWidth="1.2" strokeLinecap="round"
                style={{animation:`sparkleGomi 2.4s ${s.delay}s ease-in-out infinite`}}/>
              <line x1={s.cx} y1={s.cy-s.r*1.6} x2={s.cx} y2={s.cy+s.r*1.6}
                stroke={s.color} strokeWidth="1.2" strokeLinecap="round"
                style={{animation:`sparkleGomi 2.4s ${s.delay}s ease-in-out infinite`}}/>
            </g>
          ))}
        </svg>

      </div>
      <style>{`
        @keyframes floatUp{0%,100%{transform:translateY(0)}50%{transform:translateY(-5px)}}
        @keyframes sparkleGomi{
          0%{opacity:0;transform:scale(0.3)}
          30%{opacity:1;transform:scale(1.2)}
          60%{opacity:0.8;transform:scale(1)}
          100%{opacity:0;transform:scale(0.3)}
        }
      `}</style>
    </div>
  );
}

