        {/* Large play button circle */}
        <div style={{width:54,height:54,borderRadius:"50%",background:"rgba(255,255,255,0.92)",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 4px 16px rgba(0,0,0,0.18)"}}>
          <svg width="22" height="22" viewBox="0 0 22 22">
            <polygon points="7,4 19,11 7,18" fill={g1}/>
          </svg>
        </div>
        {/* YouTube badge */}
        <div style={{position:"absolute",bottom:8,right:10,background:"rgba(0,0,0,0.55)",borderRadius:6,padding:"3px 8px",display:"flex",alignItems:"center",gap:4}}>
          <svg width="14" height="10" viewBox="0 0 14 10"><rect width="14" height="10" rx="2" fill="#FF0000"/><polygon points="5.5,2.5 10.5,5 5.5,7.5" fill="white"/></svg>
          <span style={{color:"#fff",fontSize:10,fontWeight:600}}>YouTube</span>
        </div>
