/* ══════════════════════════════════════════════
   SETTINGS MODAL
══════════════════════════════════════════════ */
function SettingsModal({ settings, onSave, onClose }) {
  const [goal, setGoal]=useState(String(settings.goal??30));
  const [notifs, setNotifs]=useState(settings.notifications??{morning:{enabled:false,time:"06:00"},evening:{enabled:false,time:"21:00"}});
  const handleSave=()=>{onSave({goal:parseInt(goal)||0,notifications:notifs});onClose();};
  return (
    <div style={{position:"fixed",inset:0,zIndex:200,display:"flex",alignItems:"flex-end",justifyContent:"center"}}>
      <div onClick={onClose} style={{position:"absolute",inset:0,background:"rgba(0,0,0,0.3)"}}/>
      <div style={{position:"relative",background:"#fff",width:"100%",maxWidth:480,borderRadius:"24px 24px 0 0",padding:"24px 20px 44px",zIndex:1,maxHeight:"85vh",overflowY:"auto"}}>
        <div style={{width:40,height:4,background:"#E5E7EB",borderRadius:2,margin:"0 auto 20px"}}/>
        <h3 style={{color:"#2D2840",fontSize:17,fontWeight:700,margin:"0 0 20px"}}>⚙️ 설정</h3>
        <Sec title="🎯 일일 수행 목표" bg="#FFF7ED" bc="#B45309">
          <label style={LS}>하루 수행 목표 (분)</label>
          <input type="number" value={goal} onChange={e=>setGoal(e.target.value)} placeholder="예: 30"
            style={{...IS,border:"1.5px solid #FEF3C7"}}/>
          <p style={{color:"#D97706",fontSize:12,margin:"6px 0 0"}}>기록탭 캐릭터 주변에 진행률 원이 표시됩니다</p>
        </Sec>
        <Sec title="🔔 수행 알림" bg="#ECFDF5" bc="#059669">
          <p style={{color:"#9896AA",fontSize:12,margin:"0 0 12px"}}>앱이 열려있을 때 지정한 시간에 알림이 표시됩니다</p>
          {[["morning","☀️ 아침 수행 알림"],["evening","🌙 저녁 수행 알림"]].map(([type,label])=>(
            <div key={type} style={{display:"flex",alignItems:"center",gap:10,marginBottom:10,padding:"10px 14px",background:"#fff",borderRadius:12,border:"1px solid #D1FAE5"}}>
              <span style={{flex:1,fontSize:13,color:"#374151"}}>{label}</span>
              <input type="time" value={notifs[type].time} onChange={e=>setNotifs(prev=>({...prev,[type]:{...prev[type],time:e.target.value}}))}
                style={{border:"1px solid #D1FAE5",borderRadius:8,padding:"4px 8px",color:"#059669",fontSize:13,outline:"none"}}/>
              <button onClick={()=>setNotifs(prev=>({...prev,[type]:{...prev[type],enabled:!prev[type].enabled}}))}
                style={{width:44,height:24,borderRadius:12,border:"none",cursor:"pointer",position:"relative",background:notifs[type].enabled?"#34D399":"#D1D5DB",transition:"all 0.2s"}}>
                <div style={{width:18,height:18,borderRadius:"50%",background:"#fff",position:"absolute",top:3,left:notifs[type].enabled?23:3,transition:"all 0.2s"}}/>
              </button>
            </div>
          ))}
        </Sec>
        <Sec title="ℹ️ 앱 정보" bg="#F5F3FF" bc="#7C3AED">
          <p style={{color:"#6B7280",fontSize:13,margin:"0 0 3px"}}>🌸 빛꽃수행일지 v2.0</p>
          <p style={{color:"#7C3AED",fontSize:13,fontWeight:600,margin:0}}>개발 · 운영 : 증산도 대학생 연합회</p>
        </Sec>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
          <button onClick={onClose} style={{...BS,background:"#F3F4F6",color:"#6B7280",border:"none"}}>취소</button>
          <button onClick={handleSave} style={{...BS,background:"#7C3AED",color:"#fff",border:"none"}}>저장</button>
        </div>
      </div>
    </div>
  );
}

